sample=instance/num_inst;

//// eyes

c=below(sample,.5);

x=x+if(c,.2*sample,-.1+.2*sample);

y=y+.03*sin(4*x-time);
x=x+.02*sin(13*y-time);

x=x+.14*(instance%2);

rad=rad*sin(2*3.14*sample);
rad=if(c,rad,.16*rad);

r=if(c,r,0);
g=if(c,g,0);
b=if(c,b,0);

sample=instance/num_inst;

///// octopus (star)

s=.6;       p0=5;   p1=p0*s;    p2=p1%p0;    p3=6.28/p0;

x=p2-p1;    y=0;

t=sin(.4*time)+sin(.6*time)+sin(.33*time);

mx=x*sin(p2*p3+t)+y*cos(p2*p3+t);
my=y*sin(p2*p3+t)-x*cos(p2*p3+t);

d=sqrt(mx*mx+my*my);

mx=mx*(1+d*sin(50*s+time));
my=my*(1+d*sin(40*s-.7*time));

d=sqrt(mx*mx+my*my)+.2;
//rad=rad*(1+25*d);

///// tickles

s=6*sample;
p=-int(s);

s1=rad+.2*rad*sin(6.28*s);
s2=rad+.5*rad*sin(3.3+6.28*s);

x=  bnot(p)  *.1;             y=  bnot(p)  *(-.4-1.1*s);     rad=    bnot(p)  *(.25*s1);   /// l leg
x=x+bnot(p+1)*(-.1);          y=y+bnot(p+1)*(.7-1.1*s);      rad=rad+bnot(p+1)*(.25*s1);   /// r leg
x=x;                          y=y+bnot(p+2)*(-2.15+.8*s);    rad=rad+bnot(p+2)*(.5*s1);    /// body
x=x;                          y=y+bnot(p+3)*(-.65+.3*s);     rad=rad+bnot(p+3)*(.28*s2);   /// neck, head
x=x+bnot(p+4)*(-.27+.1*s);    y=y+bnot(p+4)*(3.2-.75*s);     rad=rad+bnot(p+4)*(.2*s1);    /// l arm
x=x+bnot(p+5)*(.37-.1*s);     y=y+bnot(p+5)*(4-.76*s);       rad=rad+bnot(p+5)*(.2*s1);    /// r arm


//// movement
t=3*(time+q1);

x=x+ bnot(p)   *below(y,-.9) *(-.1+x+.2*abs((y+.9)*sin(1.2*t)));                           /// l leg
x=x+ bnot(p+1) *below(y,-.9) *(.1+x-.2*abs((y+.9)*sin(1.4*t)));                            /// r leg
x=x+ bnot(p+4) *below(y,-.2) *(-.18+x-.5*abs((y+.2)*sin(t)));                              /// l arm
x=x+ bnot(p+5) *below(y,-.2) *(.18+x+.5*abs((y+.2)*sin(1.3*t)));                           /// r arm

x=x+.1*sin(y+1.8*t)*(y+1.6);                                                               /// general


x=.5+(mx+.25*x*d)/q6;
y=.5+my+.25*y*d;

rad=rad*d;

